use tower::Service;
use std::task::{Context, Poll};
use std::future::Future;
use std::pin::Pin;
use std::convert::Infallible;

struct MyClient {
    base_url: String,
}

// tower::Service<Request> is generic over the request type
impl Service<String> for MyClient {
    type Response = String;   // what the service returns on success
    type Error = Infallible;  // this service never fails
    type Future = Pin<Box<dyn Future<Output = Result<Self::Response, Self::Error>> + Send>>;

    fn poll_ready(&mut self, _cx: &mut Context<'_>) -> Poll<Result<(), Self::Error>> {
        // Return Ready if the service is prepared to handle a request
        Poll::Ready(Ok(()))
    }

    fn call(&mut self, path: String) -> Self::Future {
        let url = format!("{}{}", self.base_url, path);
        Box::pin(async move {
            Ok(format!("GET {}", url))
        })
    }
}

#[tokio::main]
async fn main() {
    use tower::ServiceExt; // for .oneshot()
    let mut svc = MyClient { base_url: "https://example.com".to_string() };
    let response = svc.ready().await.unwrap().call("/api".to_string()).await.unwrap();
    println!("{}", response);
}

