use tower::{Service, Layer};
use std::task::{Context, Poll};
use std::future::Future;
use std::pin::Pin;

struct LoggingLayer;

#[derive(Clone)]
struct LoggingService<S> {
    inner: S,
    label: &'static str,
}

// Layer<S> is generic over the inner service type S
impl<S> Layer<S> for LoggingLayer {
    type Service = LoggingService<S>; // the wrapped service type

    fn layer(&self, inner: S) -> Self::Service {
        LoggingService { inner, label: "default" }
    }
}

// Service<Req> is generic over request type Req
impl<S, Req> Service<Req> for LoggingService<S>
where
    S: Service<Req>,
    Req: std::fmt::Debug,
{
    type Response = S::Response;
    type Error = S::Error;
    type Future = S::Future;

    fn poll_ready(&mut self, cx: &mut Context<'_>) -> Poll<Result<(), Self::Error>> {
        // Delegate readiness to the inner service
        self.inner.poll_ready(cx)
    }

    fn call(&mut self, req: Req) -> Self::Future {
        println!("[{}] request: {:?}", self.label, req);
        self.inner.call(req)
    }
}

#[tokio::main]
async fn main() {
    use tower::{ServiceBuilder, ServiceExt};
    use tower::service_fn;

    let svc = ServiceBuilder::new()
        .layer(LoggingLayer)
        .service(service_fn(|req: String| async move {
            Ok::<String, std::convert::Infallible>(format!("response to {}", req))
        }));

    let mut svc = svc;
    let resp = svc.ready().await.unwrap().call("hello".to_string()).await.unwrap();
    println!("{}", resp);
}

