use std::task::{Context, Poll};
use std::future::Future;
use std::pin::Pin;

struct RateLimit<S> {
    inner: S,
    remaining: u32,
    limit: u32,
}

impl<S, Req> Service<Req> for RateLimit<S>
where
    S: Service<Req>,
{
    type Response = S::Response;
    type Error = S::Error;
    type Future = S::Future;

    fn poll_ready(&mut self, cx: &mut Context<'_>) -> Poll<Result<(), Self::Error>> {
        if self.remaining == 0 {
            self.remaining = self.limit;
        }
        self.inner.poll_ready(cx)
    }

    fn call(&mut self, req: Req) -> Self::Future {
        // ERROR: can't borrow self.inner mutably while self.remaining is also borrowed
        self.remaining -= 1;
        self.inner.call(req)  // compiler: can't move out of `self.inner` behind mutable reference in some patterns
    }
}

error_message:
// No compile error in this exact code, but the common mistake is trying to
// use self.inner after a previous borrow of self.remaining, or calling
// self.inner.call() after modifying state that held a reference to self.inner.
// The real footgun: calling `call()` without first calling `poll_ready()` on
// the inner service violates the tower::Service contract and can panic.
// poll_ready() and call() must be paired: poll_ready ensures the service is
// ready, call() consumes that readiness slot.

fixed_code:
use tower::Service;
use std::task::{Context, Poll};
use std::future::Future;
use std::pin::Pin;
use std::fmt;

#[derive(Debug)]
struct RateLimitError;
impl fmt::Display for RateLimitError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "rate limit exceeded")
    }
}
impl std::error::Error for RateLimitError {}

struct RateLimit<S> {
    inner: S,
    remaining: u32,
    limit: u32,
    ready: bool, // track whether poll_ready said we're ready
}

impl<S, Req> Service<Req> for RateLimit<S>
where
    S: Service<Req>,
    S::Error: Into<Box<dyn std::error::Error + Send + Sync>>,
{
    type Response = S::Response;
    type Error = Box<dyn std::error::Error + Send + Sync>;
    type Future = Pin<Box<dyn Future<Output = Result<Self::Response, Self::Error>> + Send>>
        where S::Future: Send;

    fn poll_ready(&mut self, cx: &mut Context<'_>) -> Poll<Result<(), Self::Error>> {
        if self.remaining == 0 {
            // Rate limit hit: signal not ready without blocking the thread
            return Poll::Ready(Err(Box::new(RateLimitError)));
        }
        // Delegate to inner — only mark ourselves ready if inner is ready
        match self.inner.poll_ready(cx) {
            Poll::Ready(Ok(())) => {
                self.ready = true;
                Poll::Ready(Ok(()))
            }
            other => other.map_err(|e| e.into()),
        }
    }

    fn call(&mut self, req: Req) -> Self::Future {
        assert!(self.ready, "call() before poll_ready()");
        self.ready = false;
        self.remaining -= 1;
        let fut = self.inner.call(req);
        Box::pin(async move { fut.await.map_err(|e| e.into()) })
    }
}

#[tokio::main]
async fn main() {
    use tower::{ServiceExt, service_fn};
    let inner = service_fn(|n: u32| async move { Ok::<u32, std::convert::Infallible>(n * 2) });
    let mut svc = RateLimit { inner, remaining: 3, limit: 3, ready: false };
    for i in 0..3 {
        let result = svc.ready().await.unwrap().call(i).await;
        println!("{:?}", result);
    }
}

