use tower::util::BoxCloneService;
use tower::{service_fn, ServiceExt};

// BoxCloneService<Req, Res, Err> is a concrete type wrapping a
// cloneable, object-safe service — it erases the concrete service type
#[derive(Clone)]
struct Router {
    service: BoxCloneService<String, String, String>,
}

impl Router {
    fn new<S>(svc: S) -> Self
    where
        S: tower::Service<String, Response = String, Error = String>
            + Clone
            + Send
            + 'static,
        S::Future: Send + 'static,
    {
        Router {
            service: BoxCloneService::new(svc),
        }
    }

    async fn handle(&mut self, req: String) -> Result<String, String> {
        self.service.ready().await?.call(req).await
    }
}

#[tokio::main]
async fn main() {
    let svc = service_fn(|req: String| async move {
        Ok::<String, String>(format!("echo: {}", req))
    });
    let mut router = Router::new(svc);
    // Router is Clone, so we can share it between tasks
    let mut router2 = router.clone();
    let (r1, r2) = tokio::join!(
        router.handle("request-1".to_string()),
        router2.handle("request-2".to_string()),
    );
    println!("{:?} {:?}", r1, r2);
}

