use tower::{Service, Layer, ServiceExt};
use std::task::{Context, Poll};
use std::future::Future;
use std::pin::Pin;
use std::time::Duration;

#[derive(Debug)]
struct TimeoutError;
impl std::fmt::Display for TimeoutError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "request timed out")
    }
}
impl std::error::Error for TimeoutError {}

#[derive(Clone)]
struct TimeoutLayer { secs: u64 }

#[derive(Clone)]
struct TimeoutService<S> { inner: S, duration: Duration }

impl<S> Layer<S> for TimeoutLayer {
    type Service = TimeoutService<S>;
    fn layer(&self, inner: S) -> Self::Service {
        TimeoutService { inner, duration: Duration::from_secs(self.secs) }
    }
}

impl<S, Req> Service<Req> for TimeoutService<S>
where
    S: Service<Req> + Send,
    S::Future: Send,
    S::Error: Into<Box<dyn std::error::Error + Send + Sync>>,
    Req: Send + 'static,
{
    type Response = S::Response;
    type Error = Box<dyn std::error::Error + Send + Sync>;
    type Future = Pin<Box<dyn Future<Output = Result<Self::Response, Self::Error>> + Send>>;

    fn poll_ready(&mut self, cx: &mut Context<'_>) -> Poll<Result<(), Self::Error>> {
        self.inner.poll_ready(cx).map_err(|e| e.into())
    }

    fn call(&mut self, req: Req) -> Self::Future {
        let fut = self.inner.call(req);
        let duration = self.duration;
        Box::pin(async move {
            tokio::time::timeout(duration, fut)
                .await
                .map_err(|_| Box::new(TimeoutError) as Box<dyn std::error::Error + Send + Sync>)?
                .map_err(|e| e.into())
        })
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use tower::{service_fn, ServiceBuilder, ServiceExt};

    #[tokio::test]
    async fn test_passes_through_fast_request() {
        // Use service_fn as a mock inner service — no real server needed
        let inner = service_fn(|req: String| async move {
            Ok::<String, std::convert::Infallible>(format!("ok: {}", req))
        });

        let mut svc = ServiceBuilder::new()
            .layer(TimeoutLayer { secs: 1 })
            .service(inner);

        // .oneshot() handles poll_ready + call + awaiting the future
        let result = svc.ready().await.unwrap()
            .call("hello".to_string())
            .await
