            Ok::<String, std::convert::Infallible>("too late".to_string())
        });

        let mut svc = ServiceBuilder::new()
            .layer(TimeoutLayer { secs: 0 }) // 0-second timeout always fires
            .service(inner);

        let result = svc.ready().await.unwrap()
            .call("slow".to_string())
            .await;
        assert!(result.is_err());
    }
